1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0]).toEqual({ premium: 5 });
13	    });
14	    it.todo("computes base premium for a single sword (100 G + 5 G fee = 105 G)");
15	    it.todo("computes base premium for a single amulet (60 G + 5 G fee = 65 G)");
16	    it.todo("computes base premium for a single staff (80 G + 5 G fee = 85 G)");
17	    it.todo("computes base premium for a single potion (40 G + 5 G fee = 45 G)");
18	    it.todo("computes base premium for a single component (25 G + 5 G fee = 30 G)");
19	    it.todo("computes base premium for multiple items (sword + amulet = 160 G + 5 G fee = 165 G)");
20	  });
21	
22	  describe("Quote - component blocks", () => {
23	    it.todo("applies block discount for exactly 3 alike components (60 G + 5 G fee = 65 G)");
24	    it.todo("does not apply block for 2 alike components (50 G + 5 G fee = 55 G)");
25	    it.todo("does not apply block for 4 alike components (100 G + 5 G fee = 105 G)");
26	    it.todo("does not apply block for 3 components of different types (75 G + 5 G fee = 80 G)");
27	    it.todo("applies two separate blocks for 3 runes + 3 moonstones (120 G + 5 G fee = 125 G)");
28	  });
29	
30	  describe("Quote - item-specific modifiers", () => {
31	    it.todo("adds 50% cursed surcharge to a cursed item's base premium");
32	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
33	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
34	    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
35	    it.todo("applies item-specific surcharges only to the affected item in a multi-item policy");
36	  });
37	
38	  describe("Quote - policy-wide modifiers", () => {
39	    it.todo("applies 10% first-insurance surcharge on policy base premium");
40	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
41	    it.todo("applies 15% follow-up contract discount on second quote");
42	    it.todo("applies loyalty, first-insurance, and follow-up modifiers together");
43	  });
44	
45	  describe("Quote - rounding", () => {
46	    it.todo("rounds premium up (in MHPCO's favor) to whole G");
47	  });
48	
49	  describe("Claim - basic payout", () => {
50	    it.todo("reimburses damage minus 100 G deductible for a regular item");
51	    it.todo("applies deductible per damaged item in a single event");
52	    it.todo("reimburses component damage minus deductible");
53	  });
54	
55	  describe("Claim - special reimbursement rules", () => {
56	    it.todo("reimburses at 50% for items with enchantment level >= 8");
57	    it.todo("fully reimburses dragon-material items");
58	    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
59	    it.todo("fully reimburses dragon-material item with enchantment < 8");
60	  });
61	
62	  describe("Claim - cap", () => {
63	    it.todo("caps total payout at twice the insurance sum");
64	    it.todo("tracks remaining cap across multiple claims on the same policy");
65	    it.todo("returns remaining cap of 0 when cap is exhausted");
66	  });
67	
68	  describe("Claim - rounding", () => {
69	    it.todo("rounds payout down (in MHPCO's favor) to whole G");
70	  });
71	
72	  describe("Error handling", () => {
73	    it.todo("rejects unknown item type in quote");
74	    it.todo("rejects claim for item not in the policy");
75	    it.todo("rejects negative damage amount");
76	    it.todo("rejects more damages of a type than insured items of that type");
77	  });
78	
79	  describe("Integration - newcomer with cursed sword", () => {
80	    it.todo("computes 165 G for a newcomer with a cursed sword");
81	  });
82	
83	  describe("Integration - long-standing customer second contract", () => {
84	    it.todo("computes 160 G for a long-standing customer's second contract with cursed high-enchantment sword");
85	  });
86	});
